     1→//! High-level statistical modeling API for Rust
     2→//!
     3→//! This crate provides familiar model-fitting APIs like `Lm` (Linear Models)
     4→//! and `Glm` (Generalized Linear Models), integrating lower-level crates
     5→//! to provide a complete modeling workflow.
     6→
     7→#![forbid(unsafe_code)]
     8→#![warn(missing_docs)]
     9→
    10→pub mod diagnostics;
    11→pub mod hypothesis_tests;
    12→pub mod intervals;
    13→
    14→use faer::{prelude::*, Mat};
    15→use family::Family;
    16→use link::LinkFn;
    17→use ndarray::{Array1, ArrayView1, ArrayView2};
    18→use optimcore::{coordinate_descent, irls, CoordinateDescentConfig, IrlsConfig};
    19→use resample::{bootstrap, BootstrapConfig, BootstrapResult, BootstrapStatistic};
    20→
    21→/// Statistical modeling errors
    22→#[derive(thiserror::Error, Debug)]
    23→pub enum ModelError {
    24→    /// Linear algebra computation error
    25→    #[error("Linear algebra error: {0}")]
    26→    LinearAlgebra(String),
    27→    /// Invalid model specification
    28→    #[error("Invalid model: {0}")]
    29→    InvalidModel(String),
    30→}
    31→
    32→// Re-export important types for convenience
    33→pub use family::{Binomial, Gaussian, Poisson};
    34→pub use link::{Identity, Log, Logit};
    35→
    36→/// Common trait for all fitted models
    37→pub trait Fit {
    38→    /// Get model coefficients
    39→    fn coefficients(&self) -> &[f64];
    40→
    41→    /// Get fitted values
    42→    fn fitted(&self) -> &[f64];
    43→
    44→    /// Get residuals
    45→    fn residuals(&self) -> &[f64];
    46→
    47→    /// Get model summary
    48→    fn summary(&self) -> ModelSummary;
    49→
    50→    /// Perform bootstrap resampling on the model
    51→    fn bootstrap(&self, _n_samples: usize) -> Result<BootstrapResult, ModelError> {
    52→        Err(ModelError::InvalidModel(
    53→            "Bootstrap not implemented for this model type".to_string(),
    54→        ))
    55→    }
    56→}
    57→
    58→/// Model summary information
    59→#[derive(Debug)]
    60→pub struct ModelSummary {
    61→    /// Coefficient table
    62→    pub coefficients: Vec<CoefficientRow>,
    63→    /// R-squared (coefficient of determination)
    64→    pub r_squared: f64,
    65→    /// Adjusted R-squared
    66→    pub adj_r_squared: f64,
    67→    /// Residual standard error
    68→    pub residual_std_error: f64,
    69→    /// F-statistic for overall model significance
    70→    pub f_statistic: f64,
    71→    /// p-value for F-statistic
    72→    pub f_p_value: f64,
    73→    /// Degrees of freedom for model (number of predictors excluding intercept)
    74→    pub df_model: usize,
    75→    /// Degrees of freedom for residuals
    76→    pub df_residual: usize,
    77→}
    78→
    79→/// A row in the coefficient table
    80→#[derive(Debug)]
    81→pub struct CoefficientRow {
    82→    /// Variable name
    83→    pub name: String,
    84→    /// Estimated coefficient
    85→    pub estimate: f64,
    86→    /// Standard error
    87→    pub std_error: f64,
    88→    /// t-statistic
    89→    pub t_value: f64,
    90→    /// p-value
    91→    pub p_value: f64,
    92→}
    93→
    94→/// Linear model fitting
    95→pub struct Lm;
    96→
    97→/// Generalized linear model fitting
    98→pub struct Glm;
    99→
   100→/// Lasso regression (L1 regularization)
   101→pub struct Lasso;
   102→
   103→/// Ridge regression (L2 regularization)
   104→pub struct Ridge;
   105→
   106→/// Fitted linear model results
   107→#[derive(Debug)]
   108→pub struct LmFit {
   109→    coefficients: Vec<f64>,
   110→    fitted_values: Vec<f64>,
   111→    residuals: Vec<f64>,
   112→    /// Number of observations
   113→    n_obs: usize,
   114→    /// Matrix rank (for rank-deficient matrices)
   115→    rank: usize,
   116→    /// Design matrix for statistical inference (stored for covariance calculation)
   117→    x_matrix: Mat<f64>,
   118→}
   119→
   120→/// Fitted generalized linear model results
   121→#[derive(Debug)]
   122→pub struct GlmFit {
   123→    coefficients: Vec<f64>,
   124→    fitted_values: Vec<f64>,
   125→    residuals: Vec<f64>,
   126→    /// Linear predictor values (X * β)
   127→    linear_predictor: Vec<f64>,
   128→    /// Number of observations
   129→    n_obs: usize,
   130→    /// Design matrix for statistical inference
   131→    x_matrix: Mat<f64>,
   132→    /// Final deviance
   133→    deviance: f64,
   134→    /// Null deviance (intercept-only model)
   135→    null_deviance: f64,
   136→    /// Working weights from final IRLS iteration
   137→    weights: Vec<f64>,
   138→    /// Number of IRLS iterations
   139→    iterations: usize,
   140→    /// Whether IRLS converged
   141→    converged: bool,
   142→    /// Family name for bootstrap
   143→    family_name: String,
   144→}
   145→
   146→/// Fitted regularized model results (Lasso/Ridge)
   147→#[derive(Debug)]
   148→pub struct RegularizedFit {
   149→    coefficients: Vec<f64>,
   150→    fitted_values: Vec<f64>,
   151→    residuals: Vec<f64>,
   152→    /// Number of observations
   153→    n_obs: usize,
   154→    /// Design matrix for bootstrap resampling
   155→    x_matrix: Mat<f64>,
   156→    /// Response vector for bootstrap resampling
   157→    y_vector: Vec<f64>,
   158→    /// Regularization parameter used
   159→    lambda: f64,
   160→    /// Elastic net mixing parameter (1.0 = Lasso, 0.0 = Ridge)
   161→    alpha: f64,
   162→    /// Number of coordinate descent iterations
   163→    pub iterations: usize,
   164→    /// Whether algorithm converged
   165→    pub converged: bool,
   166→}
   167→
   168→impl RegularizedFit {
   169→    /// Create a RegularizedFit from coordinate descent results
   170→    pub fn from_coordinate_descent(
   171→        result: optimcore::OptimResult,
   172→        x_matrix: ndarray::Array2<f64>,
   173→        y_vector: ndarray::Array1<f64>,
   174→        lambda: f64,
   175→        alpha: f64,
   176→    ) -> Self {
   177→        let n_obs = x_matrix.nrows();
   178→        
   179→        // Calculate fitted values
   180→        let fitted_values: Vec<f64> = (0..n_obs)
   181→            .map(|i| {
   182→                x_matrix.row(i).iter()
   183→                    .zip(&result.params)
   184→                    .map(|(x, beta)| x * beta)
   185→                    .sum()
   186→            })
   187→            .collect();
   188→
   189→        // Calculate residuals
   190→        let residuals: Vec<f64> = y_vector.iter()
   191→            .zip(&fitted_values)
   192→            .map(|(y, fitted)| y - fitted)
   193→            .collect();
   194→
   195→        // Convert ndarray to faer matrix
   196→        let x_mat = Mat::from_fn(n_obs, x_matrix.ncols(), |i, j| x_matrix[[i, j]]);
   197→        
   198→        RegularizedFit {
   199→            coefficients: result.params.to_vec(),
   200→            fitted_values,
   201→            residuals,
   202→            n_obs,
   203→            x_matrix: x_mat,
   204→            y_vector: y_vector.to_vec(),
   205→            lambda,
   206→            alpha,
   207→            iterations: result.iterations,
   208→            converged: result.converged,
   209→        }
   210→    }
   211→}
