   213→impl Lm {
   214→    /// Fit a linear model using ndarray views (recommended modern API)
   215→    ///
   216→    /// This implementation uses faer's column-pivoted QR decomposition to handle
   217→    /// rank-deficient design matrices robustly, as is common in statistical modeling.
   218→    ///
   219→    /// # Arguments
   220→    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
   221→    /// * `y` - Response vector as ndarray view (n_observations)
   222→    ///
   223→    /// # Example
   224→    /// ```
   225→    /// use ndarray::Array2;
   226→    /// use stats_models::Lm;
   227→    ///
   228→    /// // Create design matrix with intercept
   229→    /// let x = Array2::from_shape_vec((3, 2), vec![1.0, 1.0, 1.0, 2.0, 1.0, 3.0]).unwrap();
   230→    /// let y = vec![3.0, 5.0, 7.0];
   231→    ///
   232→    /// let fit = Lm::fit_ndarray(x.view(), ndarray::Array1::from(y).view()).unwrap();
   233→    /// ```
   234→    pub fn fit_ndarray(x: ArrayView2<f64>, y: ArrayView1<f64>) -> Result<LmFit, ModelError> {
   235→        let (n_rows, n_cols) = x.dim();
   236→
   237→        if y.len() != n_rows {
   238→            return Err(ModelError::InvalidModel(
   239→                "Response vector length doesn't match number of observations".to_string(),
   240→            ));
   241→        }
   242→
   243→        // Convert to faer matrices
   244→        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x[[i, j]]);
   245→        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y[i]);
   246→
   247→        Self::fit_internal(x_mat, y_mat, n_rows, n_cols)
   248→    }
   249→
   250→    /// Fit a linear model using raw slices (legacy API for backward compatibility)
   251→    ///
   252→    /// This implementation uses faer's column-pivoted QR decomposition to handle
   253→    /// rank-deficient design matrices robustly, as is common in statistical modeling.
   254→    ///
   255→    /// **Note**: Consider using `fit_ndarray` for better type safety and ergonomics.
   256→    pub fn fit(
   257→        x_data: &[f64],
   258→        y_data: &[f64],
   259→        n_rows: usize,
   260→        n_cols: usize,
   261→    ) -> Result<LmFit, ModelError> {
   262→        if x_data.len() != n_rows * n_cols {
   263→            return Err(ModelError::InvalidModel(
   264→                "Design matrix dimensions don't match data".to_string(),
   265→            ));
   266→        }
   267→
   268→        if y_data.len() != n_rows {
   269→            return Err(ModelError::InvalidModel(
   270→                "Response vector length doesn't match number of observations".to_string(),
   271→            ));
   272→        }
   273→
   274→        // Create faer matrices from input data
   275→        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x_data[i * n_cols + j]);
   276→        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y_data[i]);
   277→
   278→        Self::fit_internal(x_mat, y_mat, n_rows, n_cols)
   279→    }
   280→
   281→    /// Internal fitting logic shared by both APIs
   282→    fn fit_internal(
   283→        x_mat: Mat<f64>,
   284→        y_mat: Mat<f64>,
   285→        n_rows: usize,
   286→        n_cols: usize,
   287→    ) -> Result<LmFit, ModelError> {
   288→        // Use column-pivoted QR for numerical stability with rank-deficient matrices
   289→        let qr = x_mat.col_piv_qr();
   290→
   291→        // Calculate rank from R matrix diagonal elements
   292→        let r_matrix = qr.R();
   293→        let tolerance = 1e-12;
   294→        let mut rank = 0;
   295→        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
   296→            if r_matrix[(i, i)].abs() > tolerance {
   297→                rank += 1;
   298→            }
   299→        }
   300→
   301→        // Handle rank-deficient matrices by checking for numerical instability
   302→        let coefficients_mat = qr.solve_lstsq(&y_mat);
   303→
   304→        // Check for numerical instability and apply correction if needed
   305→        let has_instability =
   306→            (0..coefficients_mat.nrows()).any(|i| coefficients_mat[(i, 0)].abs() > 1e10);
   307→
   308→        let final_coefficients_mat = if has_instability {
   309→            // For rank-deficient case, set coefficients for columns beyond rank to zero
   310→            let mut corrected_coefs = Vec::new();
   311→            for i in 0..coefficients_mat.nrows() {
   312→                let coef = coefficients_mat[(i, 0)];
   313→                if coef.abs() > 1e10 {
   314→                    corrected_coefs.push(0.0);
   315→                } else {
   316→                    corrected_coefs.push(coef);
   317→                }
   318→            }
   319→            Mat::from_fn(n_cols, 1, |i, _| corrected_coefs[i])
   320→        } else {
   321→            coefficients_mat
   322→        };
   323→
   324→        // Calculate fitted values: ŷ = X * β (using corrected coefficients)
   325→        let fitted_mat = &x_mat * &final_coefficients_mat;
   326→
   327→        // Calculate residuals: e = y - ŷ
   328→        let residuals_mat = &y_mat - &fitted_mat;
   329→
   330→        // Extract results to plain Vec<f64> for API
   331→        let coefficients: Vec<f64> = (0..final_coefficients_mat.nrows())
   332→            .map(|i| final_coefficients_mat[(i, 0)])
   333→            .collect();
   334→
   335→        let fitted_values: Vec<f64> = (0..fitted_mat.nrows())
   336→            .map(|i| fitted_mat[(i, 0)])
   337→            .collect();
   338→
   339→        let residuals: Vec<f64> = (0..residuals_mat.nrows())
   340→            .map(|i| residuals_mat[(i, 0)])
   341→            .collect();
   342→
   343→        // rank is already computed above using qr.rank()
   344→
   345→        Ok(LmFit {
   346→            coefficients,
   347→            fitted_values,
   348→            residuals,
   349→            n_obs: n_rows,
   350→            rank,
   351→            x_matrix: x_mat,
   352→        })
   353→    }
   354→}
   355→
   356→impl LmFit {
   357→    /// Get the number of observations used in the model
   358→    pub fn n_obs(&self) -> usize {
   359→        self.n_obs
   360→    }
   361→
   362→    /// Get the rank of the design matrix (number of linearly independent columns)
   363→    pub fn rank(&self) -> usize {
   364→        self.rank
   365→    }
   366→
   367→    /// Get degrees of freedom for error (n_obs - rank)
   368→    pub fn df_resid(&self) -> usize {
   369→        self.n_obs.saturating_sub(self.rank)
   370→    }
   371→    
   372→    /// Compute model diagnostics
   373→    pub fn diagnostics(&self) -> diagnostics::ModelDiagnostics {
   374→        let sigma = self.sigma();
   375→        diagnostics::compute_diagnostics(&self.x_matrix, &self.residuals, sigma)
   376→    }
   377→    
   378→    /// Compute residual standard error
   379→    pub fn sigma(&self) -> f64 {
   380→        let rss: f64 = self.residuals.iter().map(|r| r * r).sum();
   381→        let df_resid = self.df_resid() as f64;
   382→        if df_resid > 0.0 {
   383→            (rss / df_resid).sqrt()
   384→        } else {
   385→            0.0
   386→        }
   387→    }
   388→    
   389→    /// Get variance-covariance matrix of parameters
   390→    pub fn vcov(&self) -> Mat<f64> {
   391→        let sigma_sq = self.sigma().powi(2);
   392→        
   393→        // Compute (X'X)^(-1)
   394→        let xtx = self.x_matrix.transpose() * &self.x_matrix;
   395→        let qr = xtx.col_piv_qr();
   396→        let identity = Mat::identity(xtx.nrows(), xtx.ncols());
   397→        let xtx_inv = qr.solve(&identity);
   398→        
   399→        // Multiply by sigma^2
   400→        Mat::from_fn(xtx_inv.nrows(), xtx_inv.ncols(), |i, j| {
   401→            sigma_sq * xtx_inv[(i, j)]
   402→        })
   403→    }
   404→    
   405→    /// Compute confidence intervals for parameters
   406→    pub fn confint(&self, level: f64) -> Result<Vec<intervals::ConfidenceInterval>, ModelError> {
   407→        let vcov = self.vcov();
   408→        let std_errors: Vec<f64> = (0..self.coefficients.len())
   409→            .map(|i| vcov[(i, i)].sqrt())
   410→            .collect();
   411→        
   412→        intervals::parameter_confidence_intervals(
   413→            &self.coefficients,
   414→            &std_errors,
   415→            Some(self.df_resid()),
   416→            level
   417→        ).map_err(|e| ModelError::InvalidModel(e))
   418→    }
   419→    
   420→    /// Compute prediction intervals for new observations
   421→    pub fn predict_interval(
   422→        &self,
   423→        x_new: &Mat<f64>,
   424→        level: f64
   425→    ) -> Result<Vec<intervals::PredictionInterval>, ModelError> {
   426→        let vcov = self.vcov();
   427→        let sigma = self.sigma();
   428→        
   429→        intervals::prediction_intervals(
   430→            x_new,
   431→            &self.coefficients,
   432→            &vcov,
   433→            sigma,
   434→            self.df_resid(),
   435→            level
   436→        ).map_err(|e| ModelError::InvalidModel(e))
   437→    }
   438→    
   439→    /// Perform Wald test
   440→    pub fn wald_test(
   441→        &self,
   442→        r_matrix: &Mat<f64>,
   443→        r_values: Option<&[f64]>
   444→    ) -> Result<hypothesis_tests::TestResult, ModelError> {
   445→        let vcov = self.vcov();
   446→        hypothesis_tests::wald_test(&self.coefficients, &vcov, r_matrix, r_values)
   447→            .map_err(|e| ModelError::InvalidModel(e))
   448→    }
   449→}
   450→
   451→impl Glm {
   452→    /// Fit a generalized linear model using ndarray views
   453→    ///
   454→    /// This implementation uses the IRLS algorithm to fit GLMs with any
   455→    /// exponential family distribution and link function.
   456→    ///
   457→    /// # Arguments
   458→    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
   459→    /// * `y` - Response vector as ndarray view (n_observations)
   460→    /// * `family` - Exponential family (Gaussian, Poisson, Binomial)
   461→    /// * `start` - Optional starting values for coefficients
   462→    /// * `config` - Optional IRLS configuration
   463→    pub fn fit_ndarray<F>(
   464→        x: ArrayView2<f64>,
   465→        y: ArrayView1<f64>,
   466→        family: F,
   467→        start: Option<Array1<f64>>,
   468→        config: Option<IrlsConfig>,
   469→    ) -> Result<GlmFit, ModelError>
   470→    where
   471→        F: Family,
   472→    {
   473→        let (n_rows, n_cols) = x.dim();
   474→
   475→        if y.len() != n_rows {
   476→            return Err(ModelError::InvalidModel(
   477→                "Response vector length doesn't match number of observations".to_string(),
   478→            ));
   479→        }
   480→
   481→        let link = family.link();
   482→
   483→        // Define closures for IRLS algorithm
   484→        let link_fn = |mu: f64| link.link(mu);
   485→        let inverse_link_fn = |eta: f64| link.inverse_link(eta);
   486→        let mu_eta_fn = |eta: f64| link.mu_eta(eta);
   487→        let variance_fn = |mu: f64| family.variance(mu);
   488→        let dev_resid_fn = |y: f64, mu: f64| family.dev_resid(y, mu);
   489→
   490→        let functions = optimcore::GlmFunctions {
   491→            link_fn,
   492→            inverse_link_fn,
   493→            mu_eta_fn,
   494→            variance_fn,
   495→            dev_resid_fn,
   496→        };
   497→
   498→        // Run IRLS algorithm
   499→        let irls_result = irls(x, y, functions, start, config)
   500→            .map_err(|e| ModelError::LinearAlgebra(e.to_string()))?;
   501→
   502→        // Calculate fitted values: μ = g⁻¹(X * β)
   503→        let fitted_values: Vec<f64> = irls_result
   504→            .linear_predictor
   505→            .iter()
   506→            .map(|&eta| inverse_link_fn(eta))
   507→            .collect();
   508→
   509→        // Calculate residuals: e = y - μ
   510→        let residuals: Vec<f64> = y
   511→            .iter()
   512→            .zip(fitted_values.iter())
   513→            .map(|(&y_val, &fitted)| y_val - fitted)
   514→            .collect();
   515→
   516→        // Convert ndarray to faer matrix for storage
   517→        let x_matrix = Mat::from_fn(n_rows, n_cols, |i, j| x[[i, j]]);
   518→
   519→        // Calculate null deviance (for intercept-only model)
   520→        let y_mean = y.mean().unwrap_or(0.0);
   521→        let null_deviance = y
   522→            .iter()
   523→            .map(|&y_val| dev_resid_fn(y_val, y_mean))
   524→            .sum();
   525→
   526→        Ok(GlmFit {
   527→            coefficients: irls_result.params.to_vec(),
   528→            fitted_values,
   529→            residuals,
   530→            linear_predictor: irls_result.linear_predictor.to_vec(),
   531→            n_obs: n_rows,
   532→            x_matrix,
   533→            deviance: irls_result.deviance,
   534→            null_deviance,
   535→            weights: irls_result.weights.to_vec(),
   536→            iterations: irls_result.iterations,
   537→            converged: irls_result.converged,
   538→            family_name: std::any::type_name::<F>().split("::").last().unwrap_or("Unknown").to_string(),
   539→        })
   540→    }
   541→}
