  1153→}
  1154→
  1155→/// Bootstrap statistic for regularized models
  1156→struct RegularizedBootstrapStatistic {
  1157→    lambda: f64,
  1158→    alpha: f64,
  1159→    n_params: usize,
  1160→}
  1161→
  1162→impl BootstrapStatistic for RegularizedBootstrapStatistic {
  1163→    fn compute(&self, x: ArrayView2<f64>, y: ArrayView1<f64>) -> Array1<f64> {
  1164→        let config = CoordinateDescentConfig {
  1165→            lambda: self.lambda,
  1166→            alpha: self.alpha,
  1167→            ..Default::default()
  1168→        };
  1169→
  1170→        match coordinate_descent(x, y, Some(config)) {
  1171→            Ok(result) => result.params,
  1172→            Err(_) => Array1::zeros(self.n_params), // Return zeros with consistent dimension
  1173→        }
  1174→    }
  1175→
  1176→    fn n_stats(&self) -> usize {
  1177→        self.n_params
  1178→    }
  1179→}
