    #[test]
    fn test_lm_fit_ndarray_api() {
        // Test the modern ndarray API
        // Simple linear regression: y = 1 + 2*x
        let x_data = ndarray::Array2::from_shape_vec(
            (3, 2),
            vec![
                1.0, 1.0, // [intercept, x1]
                1.0, 2.0, // [intercept, x2]
