    println!("R comparison script written to 'r_comparison.R'");
    println!("Run: Rscript r_comparison.R");
    println!();

    // Display expected differences
    println!("Expected Results:");
    println!("  Both models should show nearly identical results");
    println!("  Differences should be < 1e-10 (numerical precision)");
    println!("  This demonstrates stats-rs achieves R-level accuracy");
}

